  1	import * as React from 'react';
  2	import * as _ from 'lodash-es';
  3	import {
  4	  Breadcrumb,
  5	  BreadcrumbItem,
  6	  Button,
  7	  EmptyState,
  8	  EmptyStateBody,
  9	  EmptyStateVariant,
 10	  TextContent,
 11	} from '@patternfly/react-core';
 12	import { useTranslation } from 'react-i18next';
 13	import { CamelCaseWrap, K8sKind } from '@openshift-console/dynamic-plugin-sdk';
 14	import { LinkifyExternal } from '../../utils/link';
 15	import {
 16	  fetchSwagger,
 17	  getDefinitionKey,
 18	  getSwaggerPath,
 19	  SwaggerDefinition,
 20	  SwaggerDefinitions,
 21	} from '../swagger';
 22	
 23	const getRef = (definition: SwaggerDefinition): string => {
 24	  const ref = definition.$ref || _.get(definition, 'items.$ref');
 25	  const re = /^#\/definitions\//;
 26	  // Only follow JSON pointers, not external URI references.
 27	  return ref && re.test(ref) ? ref.replace(re, '') : null;
 28	};
 29	
 30	export const ExploreType: React.FC<ExploreTypeProps> = (props) => {
 31	  // Track the previously selected items to build breadcrumbs. Each history
 32	  // entry contains the name, description, and path to the definition in the
 33	  // OpenAPI document.
 34	  const [drilldownHistory, setDrilldownHistory] = React.useState([]);
 35	  const { kindObj, schema } = props;
 36	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 37	  const [allDefinitions, setAllDefinitions] =
 38	    React.useState<SwaggerDefinitions>(null);
 39	
 40	  React.useEffect(() => {
 41	    if (kindObj) {
 42	      fetchSwagger()
 43	        .then((response) => {
 44	          setAllDefinitions(response);
 45	        })
 46	        .catch((err) => {
 47	          // eslint-disable-next-line no-console
 48	          console.error('Could not fetch swagger definitions', err);
 49	        });
 50	    } else if (schema) {
 51	      setAllDefinitions({ 'custom-schema': schema });
 52	    }
 53	  }, [kindObj, schema]);
 54	
 55	  if (!kindObj && !schema) {
 56	    return null;
 57	  }
 58	
 59	  if (!allDefinitions) {
 60	    return null;
 61	  }
 62	  const currentSelection = _.last(drilldownHistory);
 63	  // Show the current selected property or the top-level definition for the kind.
 64	  const currentPath = currentSelection
 65	    ? currentSelection.path
 66	    : [kindObj ? getDefinitionKey(kindObj, allDefinitions) : 'custom-schema'];
 67	  const currentDefinition: SwaggerDefinition = _.get(
 68	    allDefinitions,
 69	    currentPath,
 70	  );
 71	  const currentProperties =
 72	    currentDefinition?.properties ||
 73	    currentDefinition?.items?.properties ||
 74	    currentDefinition?.definitions;
 75	
 76	  // Prefer the description saved in `currentSelection`. It won't always be defined in the definition itself.
 77	  const description = currentSelection
 78	    ? currentSelection?.description
 79	    : currentDefinition?.description;
 80	  const required = new Set(currentDefinition?.required || []);
 81	  const kindLabel = kindObj?.labelKey ? t(kindObj.labelKey) : kindObj?.kind;
 82	  const breadcrumbs = drilldownHistory.length
 83	    ? [kindObj ? kindLabel : t('Schema'), ..._.map(drilldownHistory, 'name')]
 84	    : [];
 85	
 86	  const drilldown = (
 87	    e: React.MouseEvent<HTMLButtonElement>,
 88	    name: string,
 89	    desc: string,
 90	    path: string[],
 91	  ) => {
 92	    e.preventDefault();
 93	    setDrilldownHistory([
 94	      ...drilldownHistory,
 95	      { name, description: desc, path },
 96	    ]);
 97	    if (props.scrollTop) {
 98	      props.scrollTop();
 99	    }
100	  };
101	
102	  const breadcrumbClicked = (
103	    e: React.MouseEvent<HTMLButtonElement>,
104	    i: number,
105	  ) => {
106	    e.preventDefault();
107	    setDrilldownHistory(_.take(drilldownHistory, i));
108	  };
109	
110	  // Get the path in the swagger document to additional property details for drilldown.
111	  // This can be
112	  // - A reference to another top-level definition
113	  // - Inline property declartions
114	  // - Inline property declartions for array items
115	  const getDrilldownPath = (name: string): string[] => {
116	    const path = kindObj
117	      ? currentDefinition.items
118	        ? getSwaggerPath(allDefinitions, [...currentPath, 'items'], name, true)
119	        : getSwaggerPath(allDefinitions, currentPath, name, true)
120	      : [...currentPath, 'properties', name];
121	
122	    // Only allow drilldown if the reference has additional properties to explore.
123	    const child = _.get(allDefinitions, path) as SwaggerDefinition;
124	    return _.has(child, 'properties') || _.has(child, 'items.properties')
125	      ? path
126	      : null;
127	  };
128	
129	  // Get the type to display for a property reference.
130	  const getTypeForRef = (ref: string): string =>
131	    _.get(allDefinitions, [ref, 'format']) ||
132	    _.get(allDefinitions, [ref, 'type']);
133	
134	  return (
135	    <>
136	      {!_.isEmpty(breadcrumbs) && (
137	        <Breadcrumb className="co-breadcrumb co-break-word">
138	          {breadcrumbs.map((crumb, i) => {
139	            const isLast = i === breadcrumbs.length - 1;
140	            return (
141	              <BreadcrumbItem key={i} isActive={isLast}>
142	                {isLast ? (
143	                  crumb
144	                ) : (
145	                  <Button
146	                    type="button"
147	                    onClick={(e) => breadcrumbClicked(e, i)}
148	                    isInline
149	                    variant="link"
150	                  >
151	                    {crumb}
152	                  </Button>
153	                )}
154	              </BreadcrumbItem>
155	            );
156	          })}
157	        </Breadcrumb>
158	      )}
159	      <TextContent>
160	        {description && (
161	          <p className="co-break-word co-pre-wrap">
162	            <LinkifyExternal>{description}</LinkifyExternal>
163	          </p>
164	        )}
165	        {_.isEmpty(currentProperties) ? (
166	          <EmptyState variant={EmptyStateVariant.xs}>
167	            <EmptyStateBody>{t('No Properties found')}</EmptyStateBody>
168	          </EmptyState>
169	        ) : (
170	          <ul className="co-resource-sidebar-list pf-v6-c-list">
171	            {_.map(
172	              currentProperties,
173	              (definition: SwaggerDefinition, name: string) => {
174	                const path = getDrilldownPath(name);
175	                const definitionType =
176	                  definition.type || getTypeForRef(getRef(definition));
177	                const definitionTypeStr = Array.isArray(definitionType)
178	                  ? definitionType.join(' ')
179	                  : definitionType;
180	
181	                return (
182	                  <li key={name} className="co-resource-sidebar-item">
183	                    <h5 className="co-resource-sidebar-item__header co-break-word">
184	                      <CamelCaseWrap value={name} />
185	                      &nbsp;
186	                      <small>
187	                        <span className="co-break-word">
188	                          {definitionTypeStr}
189	                        </span>
190	                        {required.has(name) && <> &ndash; required</>}
191	                      </small>
192	                    </h5>
193	                    {definition.description && (
194	                      <p className="co-break-word co-pre-wrap">
195	                        <LinkifyExternal>
196	                          {definition.description}
197	                        </LinkifyExternal>
198	                      </p>
199	                    )}
200	                    {path && (
201	                      <Button
202	                        type="button"
203	                        onClick={(e) =>
204	                          drilldown(e, name, definition.description, path)
205	                        }
206	                        isInline
207	                        variant="link"
208	                      >
209	                        {t('View details')}
210	                      </Button>
211	                    )}
212	                  </li>
213	                );
214	              },
215	            )}
216	          </ul>
217	        )}
218	      </TextContent>
219	    </>
220	  );
221	};
222	
223	type ExploreTypeProps = {
224	  kindObj: K8sKind;
225	  schema?: any;
226	  scrollTop?: () => void;
227	};

